<?php namespace App\Http\Controllers\Api\Admin; use App\Http\Controllers\Controller; use App\Models\Category; use Illuminate\Http\Request; class AdminCategoryController extends Controller { public function index() { return Category::all(); } public function store(Request $request) { return Category::create($request->all()); } public function update(Request $request, Category $category) { $category->update($request->all()); return $category; } public function destroy(Category $category) { $category->delete(); return response()->noContent(); } }